@import './theme.css';
@import './utilities.css';

.react-aria-DateField {
  display: flex;
  flex-direction: column;
}

.react-aria-DateInput {
  display: inline;
  padding: 0 var(--spacing-3);
  box-sizing: border-box;
  border-radius: var(--radius);
  font: var(--font-size) system-ui;
  color: var(--field-text-color);
  height: var(--spacing-8);
  line-height: var(--spacing-8);
  width: fit-content;
  min-width: 150px;
  white-space: nowrap;
  forced-color-adjust: none;
  cursor: text;

  &[data-focus-within] {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: -1px;
  }

  &[data-disabled] {
    color: var(--text-color-disabled);
    cursor: default;
  }
}

.react-aria-DateSegment {
  padding: 2px;
  font-size: var(--font-size);
  font-variant-numeric: tabular-nums;
  text-align: end;
  color: var(--field-text-color);
  -webkit-tap-highlight-color: transparent;

  &[data-type='literal'] {
    padding: 0;
  }

  &[data-placeholder] {
    color: var(--text-color-placeholder);
  }

  &:focus {
    color: var(--highlight-foreground);
    background: var(--highlight-background);
    outline: none;
    border-radius: 4px;
    caret-color: transparent;
  }

  &[data-invalid] {
    color: var(--invalid-color);

    &:focus {
      background: var(--highlight-background-invalid);
      color: var(--highlight-foreground);
    }
  }

  &[data-disabled] {
    color: var(--text-color-disabled);
    cursor: default;
  }
}

@import './theme.css';

.react-aria-Popover {
  --background-color: var(--overlay-background);

  outline: 1px solid var(--overlay-border);
  box-sizing: border-box;
  filter: drop-shadow(var(--popover-shadow));
  border-radius: var(--radius-lg);
  background: var(--background-color);
  color: var(--text-color);
  transition:
    transform 200ms,
    opacity 200ms;
  font: var(--font-size) system-ui;
  padding: 8px;

  &[data-trigger='MenuTrigger'],
  &[data-trigger='SubmenuTrigger'] {
    padding: 0;
  }

  .react-aria-OverlayArrow svg {
    display: block;
    fill: var(--background-color);
    stroke: var(--overlay-border);
    paint-order: stroke;
    stroke-width: 2px;
  }

  &[data-entering],
  &[data-exiting] {
    transform: var(--origin);
    opacity: 0;
  }

  &[data-placement='top'] {
    --origin: translateY(8px);

    &:has(.react-aria-OverlayArrow) {
      margin-bottom: 6px;
    }
  }

  &[data-placement='bottom'] {
    --origin: translateY(-8px);

    &:has(.react-aria-OverlayArrow) {
      margin-top: 6px;
    }

    .react-aria-OverlayArrow svg {
      transform: rotate(180deg);
    }
  }

  &[data-placement='right'] {
    --origin: translateX(-8px);

    &:has(.react-aria-OverlayArrow) {
      margin-left: 6px;
    }

    .react-aria-OverlayArrow svg {
      transform: rotate(90deg);
    }
  }

  &[data-placement='left'] {
    --origin: translateX(8px);

    &:has(.react-aria-OverlayArrow) {
      margin-right: 6px;
    }

    .react-aria-OverlayArrow svg {
      transform: rotate(-90deg);
    }
  }
}

@keyframes processing {
  0% {
    opacity: 0.6;
    transform: scale(0);
  }

  100% {
    opacity: 0;
    transform: scale(2.8);
  }
}

.root {
  --indicator-size: 10px;
  --indicator-color: var(--mantine-primary-color-filled);

  position: relative;
  display: block;

  &:where([data-inline]) {
    display: inline-block;
  }
}

.indicator {
  position: absolute;
  top: var(--indicator-top);
  left: var(--indicator-left);
  right: var(--indicator-right);
  bottom: var(--indicator-bottom);
  transform: translate(var(--indicator-translate-x), var(--indicator-translate-y));
  min-width: var(--indicator-size);
  height: var(--indicator-size);
  border-radius: var(--indicator-radius, 1000rem);
  z-index: var(--indicator-z-index, 200);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--mantine-font-size-xs);
  background-color: var(--indicator-color);
  color: var(--indicator-text-color, var(--mantine-color-white));
  white-space: nowrap;

  &::before {
    content: '';
    position: absolute;
    inset: 0;
    background-color: var(--indicator-color);
    border-radius: var(--indicator-radius, 1000rem);
    z-index: -1;
  }

  &:where([data-with-label]) {
    padding-inline: calc(var(--mantine-spacing-xs) / 2);
  }

  &:where([data-with-border]) {
    border: 2px solid var(--mantine-color-body);
  }

  &[data-processing] {
    &::before {
      animation: processing 1000ms linear infinite;
    }
  }
}

@layer components {
  .AccordionWebsiteRoot {
    border-top: 1px solid var(--gray-t2);
  }

  .AccordionWebsiteItem {
    box-sizing: border-box;
    border-bottom: 1px solid var(--gray-t2);
  }

  .AccordionWebsiteHeader {
    margin: 0;
  }

  .AccordionWebsiteTrigger {
    box-sizing: border-box;
    position: relative;
    display: flex;
    width: 100%;
    gap: 1rem;
    align-items: center;
    justify-content: space-between;
    color: inherit;
    font-family: inherit;
    background-color: transparent;
    font-size: 1rem;
    padding-block: 0.75rem;
    padding-inline: 0;
    line-height: 1.5rem;
    border: none;
    outline: none;
    text-align: left;
    -webkit-tap-highlight-color: transparent;
  }

  .AccordionWebsiteTrigger:focus-visible {
    outline: 2px solid currentColor;
  }

  .AccordionWebsiteIconMinus {
    display: none;
  }

  .AccordionWebsiteIconPlus {
    display: block;
  }

  .AccordionWebsiteTrigger[data-panel-open] .AccordionWebsiteIconPlus {
    display: none;
  }

  .AccordionWebsiteTrigger[data-panel-open] .AccordionWebsiteIconMinus {
    display: block;
  }

  .AccordionWebsitePanel {
    padding-block-start: 4px;
    padding-block-end: 12px;
  }
}
